diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..73c68f80344e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3328,6 +3328,61 @@ static Value *foldAndOrOfICmpEqConstantAndICmp(ICmpInst *LHS, ICmpInst *RHS,
       Other);
 }

+/// Fold (X == C) | ((X & Mask) == C+1) into (X - C) <u Size+1
+/// where Mask is a negated power of 2 (like -32) and (C+1) & Mask == C+1.
+/// This combines a single value C with a masked range [C+1, C+1+~Mask].
+static Value *foldOrOfEqAndMaskedEq(ICmpInst *LHS, ICmpInst *RHS,
+                                    InstCombiner::BuilderTy &Builder) {
+  // Only for OR, not AND
+  Value *LHS0 = LHS->getOperand(0);
+  Value *RHS0 = RHS->getOperand(0);
+  Value *LHS1 = LHS->getOperand(1);
+  Value *RHS1 = RHS->getOperand(1);
+
+  // Check LHS is (X == C) - equality with constant
+  const APInt *C;
+  if (LHS->getPredicate() != ICmpInst::ICMP_EQ ||
+      !match(LHS1, m_APInt(C)) ||
+      !LHS0->getType()->isIntOrIntVectorTy())
+    return nullptr;
+
+  // Check RHS is ((X & Mask) == V) - equality with masked value
+  Value *X, *MaskVal;
+  const APInt *V;
+  if (RHS->getPredicate() != ICmpInst::ICMP_EQ ||
+      !match(RHS0, m_And(m_Value(X), m_Value(MaskVal))) ||
+      !match(RHS1, m_APInt(V)))
+    return nullptr;
+
+  // Both comparisons must use the same variable X
+  if (X != LHS0)
+    return nullptr;
+
+  // Mask must be a constant negated power of 2 (like -32 = 0xFFFFFFE0)
+  const APInt *Mask;
+  if (!match(MaskVal, m_APInt(Mask)) || !Mask->isNegatedPowerOf2())
+    return nullptr;
+
+  // V must equal C + 1
+  APInt CPlus1 = *C + 1;
+  if (*V != CPlus1)
+    return nullptr;
+
+  // (C + 1) must be aligned to the mask: (C+1) & Mask == C+1
+  if ((CPlus1 & *Mask) != CPlus1)
+    return nullptr;
+
+  // Require one-use to avoid creating more instructions
+  if (!LHS->hasOneUse() || !RHS->hasOneUse())
+    return nullptr;
+
+  // Size of the masked range is ~Mask + 1
+  // Combined range is [C, C + 1 + ~Mask], which is (X - C) <u (2 + ~Mask)
+  APInt Size = ~*Mask + 2;
+  Value *Sub = Builder.CreateSub(LHS0, ConstantInt::get(LHS0->getType(), *C));
+  return Builder.CreateICmpULT(Sub, ConstantInt::get(LHS0->getType(), Size));
+}
+
 /// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
 /// If IsLogical is true, then the and/or is in select form and the transform
 /// must be poison-safe.
@@ -3539,6 +3594,13 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     return Builder.createIsFPClass(X, IsAnd ? FPClassTest::fcNormal
                                             : ~FPClassTest::fcNormal);

+  // Try to fold (X == C) | ((X & Mask) == C+1) into (X - C) <u Size+1
+  if (!IsAnd && !IsLogical) {
+    if (Value *V = foldOrOfEqAndMaskedEq(LHS, RHS, Builder))
+      return V;
+    if (Value *V = foldOrOfEqAndMaskedEq(RHS, LHS, Builder))
+      return V;
+  }
   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }

